head.script:
//---------------------------------------------------------
// 전역변수
//---------------------------------------------------------   
scwin.hd_kcomcd = "DBEX";
scwin.hd_iogb = "O";

scwin.p_kcomcd;
scwin.p_blno;
scwin.p_mhno;
scwin.p_clntNo;
scwin.userClsCd;

scwin.onpageload = function () {
    /*
    const codeOptions = [
        { grpCd: "", compID: "" } 
    ];
    $c.data.setCommonCode(codeOptions, scwin.setInit);
    */
};

//---------------------------------------------------------
// UDC
//---------------------------------------------------------    
scwin.onUdcCompleted = function () {
    scwin.p_kcomcd = $c.data.getParameter("kcomcd");
    scwin.p_blno = $c.data.getParameter("blno");
    scwin.p_mhno = $c.data.getParameter("mhno");

    let memJson = $c.data.getMemInfo();
    console.log("### onpageload :: " + JSON.stringify(memJson));
    scwin.userClsCd = memJson.userClsCd;
    ed_custcd.setValue(memJson.clntNo);
    if (ed_custcd.getValue() != "") {
        scwin.f_PopUp("Consolidator", "T", "F", "F");
    }

    var yaho = $c.gus.dsCommonUtil("getCompanyInfoDTO", memJson.lobranCd);
    clntNo = yaho[0].value.split("clntNo = [")[1].split("]")[0];
    ed_custcd.setValue(clntNo);
    scwin.udc_cust_onviewchangeCodeEvent();

    scwin.f_getParametrSetting(); // link처리	  
}
//---------------------------------------------------------
// 사용자 함수
//---------------------------------------------------------   
scwin.codeCallbackFunc = function () {

}

scwin.f_getParametrSetting = function () {
    var kcomcd = scwin.p_kcomcd;
    var blno = scwin.p_blno;
    var mhno = scwin.p_mhno;

    if (blno == null || blno == '') {
        return false;
    }
    scwin.hd_kcomcd = kcomcd;
    ed_blno.setValue(blno);
    scwin.f_MhnoLoading();
}

scwin.f_PopUp = function (disGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {

    var codeVal = ed_custcd.getValue();
    var nameVal = txt_conm.getValue();

    ed_custcd.setValue("");
    txt_conm.setValue("");
    txt_add1.setValue("");
    txt_add2.setValue("");
    txt_add3.setValue("");
    txt_add4.setValue("");

    switch (disGubun) {
        case "Consolidator":		//Search Customer
            udc_cust.setSelectId("retrieveEngClntInfo");
            udc_cust.ilCommonPopUp(scwin.udc_cust_callbackFunc,
                codeVal,            // 화면에서의 ??? Code Element의	Value                                  
                nameVal,                // 화면에서의 ??? Name Element의	Value                                  
                pWinCloseTF,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '6',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Consolidator',                      // Title순서	                                                           
                '140,300',                      // 보여주는 각 컬럼들의 폭	                                               
                null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                pAllSearchTF,                   // 전체검색허용여부	("F")                                                  
                null,                            // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  
                pNoDataCloseTF);

            break;
        default:
            break;
    }

}

scwin.udc_cust_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_custcd, txt_conm, [txt_add1, txt_add2, txt_add3, txt_add4]);
}

scwin.f_MhnoLoading = function () {
    var strClntNo = "";
    strClntNo = ed_blno.getValue();
    param1 = "";
    if (strClntNo.length > 0) {
        param1 = strClntNo;
    } else {
        ds_mhno.removeAll();
    }
    const params = {
        sysCd: "ilCommonEBC",
        queryId: "retriveAirHouseMhnoListCombo",
        param1: param1,
    };

    //데이터셋에 정보설정
    dma_mhno.setJSON(params);

    $c.sbm.execute(sbm_mhno);
}

scwin.f_openPgm = function (name) {

    switch (name) {

        case "AirExportHouseBL":
            var src = "";
            var menuId = "11111";
            if (ed_blno.getValue() == null || ed_blno.getValue() == "") {
                $c.win.alert("Input House B/L No");
                break;
            }
            src = "/ui/il/airout/aobl/ar_104_01_01b.xml";
            paramObj = {};
            paramObj = {
                cvsslMgntNo: ""
                , kcomcd: ""
                , blno: ed_blno.getValue()
                , mblno: ""
                , type: ""
            }

            $c.win.openMenu("Export House B/L", src, menuId, paramObj);
            break;

        default:

            break;
    }

}

scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects([tb_searchCondition]);
    ds_mhno.removeAll();

    //default 동부국제물류
    ed_custcd.setValue(scwin.p_clntNo);
    if (ed_custcd.getValue() != "") {
        scwin.f_PopUp("Consolidator", "T", "F", "F");
    }
    ed_blno.focus();
}

scwin.f_Print = function () {
    var as_arranged = chb_arranged.getValue();
    var as_agreed = chb_agreed.getValue();
    var blType = lc_regb.getValue();
    if (scwin.userClsCd != "01") {
        ds_printCondition.set("kcomcd", scwin.hd_kcomcd);
        ds_printCondition.set("blno", ed_blno.getValue());
        ds_printCondition.set("mhno", lc_mhno.getValue());
        ds_printCondition.set("seaAirCls", "A");
        ds_printCondition.set("mblHblCls", "H");

        $c.sbm.execute(sbm_RetrieveBlPrintAdmission);
    } else if (scwin.userClsCd == "01") {
        var data = {};
        sReportName = "";
        if (lc_blgb.getSelectedIndex() == 0) {
            sReportName = "/il/airout/ar_104_01_06.ozr";
        } else {
            sReportName = "/il/airout/ar_104_01_05.ozr";
        }
        data = {
            odiName: "ar_104_01_05",
            reportName: sReportName,
            odiParam: {
                KCOMCD: scwin.hd_kcomcd
                , BLNO: ed_blno.getValue()
                , MHNO: lc_mhno.getValue()
                , AS_AGREED: as_agreed
                , AS: as_arranged
                , PRINT_TYPE: blType
                , COM_NM: txt_conm.getValue()
                , COM_ADDR1: txt_add1.getValue()
                , COM_ADDR2: txt_add2.getValue()
                , COM_ADDR3: txt_add3.getValue()
                , COM_ADDR4: txt_add4.getValue()
            },
            viewerParam: {
                useprogressbar: false, // 프로그레스바 쓸지 말지
                printcommand: true,
                zoom: 90, // 배율 설정
            },
            formParam: {}
        };
        console.log(JSON.stringify(data, null, 4));
        scwin.openOzReportPopup(data);
    }
}

scwin.f_Print2 = function () {
    var as_arranged = chb_arranged.getValue();
    var as_agreed = chb_agreed.getValue();
    var blType = lc_regb.getValue();
    if (scwin.userClsCd != "01") {
        ds_printCondition.set("kcomcd", scwin.hd_kcomcd);
        ds_printCondition.set("blno", ed_blno.getValue());
        ds_printCondition.set("mhno", lc_mhno.getValue());
        ds_printCondition.set("seaAirCls", "A");
        ds_printCondition.set("mblHblCls", "H");

        $c.sbm.execute(sbm_RetrieveBlPrintAdmission);
    } else if (scwin.userClsCd == "01") {
        var data = {};
        sReportName = "";
        if (lc_blgb.getSelectedIndex() == 0) {
            sReportName = "/il/airout/ar_104_01_06.ozr";
        } else {
            sReportName = "/il/airout/ar_104_01_07.ozr";
        }
        data = {
            odiName: "ar_104_01_05",
            reportName: sReportName,
            odiParam: {
                KCOMCD: scwin.hd_kcomcd
                , BLNO: ed_blno.getValue()
                , MHNO: lc_mhno.getValue()
                , AS_AGREED: as_agreed
                , AS: as_arranged
                , PRINT_TYPE: blType
                , COM_NM: txt_conm.getValue()
                , COM_ADDR1: txt_add1.getValue()
                , COM_ADDR2: txt_add2.getValue()
                , COM_ADDR3: txt_add3.getValue()
                , COM_ADDR4: txt_add4.getValue()
            },
            viewerParam: {
                useprogressbar: false, // 프로그레스바 쓸지 말지
                printcommand: true,
                zoom: 90, // 배율 설정
            },
            formParam: {}
        };
        console.log(JSON.stringify(data, null, 4));
        scwin.openOzReportPopup(data);
    }
}

scwin.openOzReportPopup = async function (data) {
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
}
//---------------------------------------------------------
// 컴포넌트 이벤트
//---------------------------------------------------------   
scwin.sbm_mhno_submitdone = function (e) {
    if (e.responseJSON.GAUCE) {
        ds_mhno.setJSON(e.responseJSON.GAUCE);
    }
    ds_mhno.sort("code", 0);
    lc_mhno.focus();
};

scwin.udc_cust_onclickEvent = function (e) {
    scwin.f_PopUp('Consolidator', 'F', 'F', 'F');
};

scwin.udc_cust_onviewchangeCodeEvent = function (info) {

    var strClntNo = ed_custcd.getValue();
    if (strClntNo.length > 0) {
        txt_conm.setValue("");
        scwin.f_PopUp("Consolidator", "T", "F", "F");
    } else {
        txt_conm.setValue("");
        txt_add1.setValue("");
        txt_add2.setValue("");
        txt_add3.setValue("");
        txt_add4.setValue("");
    }
};

scwin.btn_dimens_onclick = function (e) {
    scwin.f_openPgm('AirExportHouseBL');
};

scwin.btn_clear_onclick = function (e) {
    lc_blgb.setSelectedIndex(0);
    lc_regb.setSelectedIndex(0);
    chb_agreed.setValue("");
    chb_arranged.setValue("");
    ed_blno.setValue("");
    txt_conm.setValue("");
    txt_add1.setValue("");
    txt_add2.setValue("");
    txt_add3.setValue("");
    txt_add4.setValue("");
    ed_custcd.setValue("");
    ed_custNm.setValue("");
    ds_mhno.removeAll();

    //default 동부국제물류
    ed_custcd.setValue(scwin.p_clntNo || "NULL");
    if (ed_custcd.getValue() != "") {
        scwin.f_PopUp("Consolidator", "T", "F", "F");
    }
    ed_blno.focus();
};

scwin.btn_print_onclick = function (e) {
    scwin.f_Print();
};

scwin.btn_print2_onclick = function (e) {
    scwin.f_Print2();
};

scwin.sbm_RetrieveBlPrintAdmission_submitdone = function (e) {
    var as_arranged = chb_arranged.getValue();
    var as_agreed = chb_agreed.getValue();
    var blType = lc_regb.getValue();
    if (scwin.userClsCd != "01") {
        if (ds_printResult.getTotalRow() == 0 || ds_printResult.Namevalue(1, "issueYn") == 0) {
            $c.win.alert("해당 B/L은 발행 승인이 되지 않은 B/L입니다. \n"
                + "Export House B/L 화면에서 발행 승인 후 Print가 가능합니다.");
            return;
        } else {
            var data = {};
            sReportName = "";
            if (lc_blgb.getSelectedIndex() == 0) {
                sReportName = "/il/airout/ar_104_01_06.ozr";
            } else {
                sReportName = "/il/airout/ar_104_01_07.ozr";
            }
            data = {
                odiName: "ar_104_01_05",
                reportName: sReportName,
                odiParam: {
                    KCOMCD: scwin.hd_kcomcd
                    , BLNO: ed_blno.getValue()
                    , MHNO: lc_mhno.getValue()
                    , AS_AGREED: as_agreed
                    , AS: as_arranged
                    , PRINT_TYPE: blType
                    , COM_NM: txt_conm.getValue()
                    , COM_ADDR1: txt_add1.getValue()
                    , COM_ADDR2: txt_add2.getValue()
                    , COM_ADDR3: txt_add3.getValue()
                    , COM_ADDR4: txt_add4.getValue()
                },
                viewerParam: {
                    useprogressbar: false, // 프로그레스바 쓸지 말지
                    printcommand: true,
                    zoom: 90, // 배율 설정
                },
                formParam: {}
            };
            console.log(JSON.stringify(data, null, 4));
            scwin.openOzReportPopup(data);
        }
    }
}

scwin.ed_blno_onviewchange = function (info) {
    if (this.getValue() == "") {
        ds_mhno.removeAll();
        return;
    }
    scwin.f_MhnoLoading();
};

scwin.oneditkeyup = function (info, e) {
    this.setValue(e.target.value.toUpperCase());
};
